// Generated by Cursor AI for jjmil on 2026-03-12.
// Controller vibration for flipper activation and ball collisions.

using System.Collections;
using UnityEngine;
using UnityEngine.InputSystem;

public class HapticManager : MonoBehaviour
{
    public static HapticManager Instance { get; private set; }

    [Header("Flipper Vibration")]
    [SerializeField] private float flipperLowFrequency = 0.3f;
    [SerializeField] private float flipperHighFrequency = 0.2f;
    [SerializeField] private float flipperDuration = 0.05f;

    [Header("Launcher Vibration")]
    [SerializeField] private float launcherLowFrequency = 0.4f;
    [SerializeField] private float launcherHighFrequency = 0.3f;
    [SerializeField] private float launcherDuration = 0.08f;

    [Header("UI Navigation Vibration")]
    [SerializeField] private float uiNavLowFrequency = 0.15f;
    [SerializeField] private float uiNavHighFrequency = 0.1f;
    [SerializeField] private float uiNavDuration = 0.03f;

    [Header("Ball Collision Vibration (general)")]
    [SerializeField] private float collisionLowFrequency = 0.2f;
    [SerializeField] private float collisionHighFrequency = 0.15f;
    [SerializeField] private float collisionDuration = 0.04f;

    [Header("Ball Collision Vibration (component hit)")]
    [SerializeField] private float componentLowFrequency = 0.6f;
    [SerializeField] private float componentHighFrequency = 0.5f;
    [SerializeField] private float componentDuration = 0.08f;

    private Coroutine _stopVibrationCoroutine;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            Destroy(gameObject);
            return;
        }

        Instance = this;
        DontDestroyOnLoad(gameObject);
    }

    public void PlayFlipperHaptic()
    {
        TriggerHaptic(flipperLowFrequency, flipperHighFrequency, flipperDuration);
    }

    public void PlayLaunchHaptic()
    {
        TriggerHaptic(launcherLowFrequency, launcherHighFrequency, launcherDuration);
    }

    public void PlayUINavigationHaptic()
    {
        TriggerHaptic(uiNavLowFrequency, uiNavHighFrequency, uiNavDuration);
    }

    public void PlayCollisionHaptic(bool isComponent)
    {
        if (isComponent)
        {
            TriggerHaptic(componentLowFrequency, componentHighFrequency, componentDuration);
        }
        else
        {
            TriggerHaptic(collisionLowFrequency, collisionHighFrequency, collisionDuration);
        }
    }

    private void TriggerHaptic(float low, float high, float duration)
    {
#if ENABLE_INPUT_SYSTEM
        if (Gamepad.current == null)
        {
            return;
        }

        if (_stopVibrationCoroutine != null)
        {
            StopCoroutine(_stopVibrationCoroutine);
        }

        Gamepad.current.SetMotorSpeeds(low, high);
        _stopVibrationCoroutine = StartCoroutine(StopVibrationAfter(duration));
#endif
    }

    private IEnumerator StopVibrationAfter(float duration)
    {
        yield return new WaitForSecondsRealtime(duration);

#if ENABLE_INPUT_SYSTEM
        if (Gamepad.current != null)
        {
            Gamepad.current.SetMotorSpeeds(0f, 0f);
        }
#endif

        _stopVibrationCoroutine = null;
    }
}
